module clock_divider(  
    input wire clk_in,  
    input wire rst,  
    output reg clk_out  
);  
    reg [1:0] unused_count;  

    always @(posedge clk_in or posedge rst) begin  
        if (rst) begin  
            unused_count <= 2'b00;  
            clk_out <= 0;  
        end else begin  
            unused_count <= unused_count + 1;  
            if (unused_count == 2'b11) begin  
                clk_out <= ~clk_out;  
            end  
        end  
    end  
endmodule
